  ('judicial-57112235-moex-00223', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'essay', '監所舍房建築之內部型式及其特色為何，請說明之。（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00224', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關犯罪矯正之歷史發展，下列敘述何者錯誤？', '["獄政之發展係與當時代之社會風俗、習慣、法律與政治體制有密切相關性", "十八世紀理性啟蒙時代來臨，獄政逐漸拋棄酷刑，以罪刑均衡為原則", "十九世紀以後至二十世紀初期，因尚無實證主義之思維，故獄政仍以專橫為主，未趨於仁道", "犯罪矯正發展逐漸朝向仁道化與科學化之道路邁進，個別化處遇之應用即為最重要的發展之一"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00225', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關監獄調查分類制度實施，下列敘述何者錯誤？', '["實施新收講習有助收容人適應監禁生活", "調查分類僅作為將受刑人分門別類，而後加以分別監禁之方法", "新收調查期間進行健康檢查，具有維護監獄職員及其他受刑人身體健康，防範傳染疾病風險", "探求個案犯罪原因與人格特質，加以分析研判，擬訂個別處遇計畫"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00226', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '關於受刑人「工作外出制度」，下列敘述何者正確？', '["首先推出係由美國威斯康辛州於1913年通過休博法（HuberAct），給予長刑期受刑人工作外出之制度", "係准許受刑人於白天在戒護下外出到自由社會工作的制度，不包括無戒護下的工作外出", "係專指由法官判決時宣判的中間型刑罰，非由行政當局得自由裁量", "起初僅施用於短期自由刑者，因成效良好，目前已逐漸擴大施用於重刑犯 20620"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
